@page "/apply"
@using sv_969d204f784e4c4a9b40f775110a1e76.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="step-indicator mb-4" aria-label="Application steps">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var step = i + 1;
            var label = StepLabels[i];
            var isCurrent = step == currentStep;
            var isCompleted = step < currentStep || submitted;
            var isFuture = step > currentStep;

            <button class="step-item @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                    disabled="@(isFuture || submitted)"
                    @onclick="() => GoToStep(step)">
                <span class="step-circle">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </span>
                <span class="step-label">@label</span>
            </button>

            @if (i < StepLabels.Length - 1)
            {
                <span class="step-connector @(step < currentStep ? "completed" : "")"></span>
            }
        }
    </nav>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger" role="alert">@errorMessage</div>
    }

    @* ───── Step 1: Personal Info ───── *@
    @if (currentStep == 1)
    {
        <section>
            <h4>Personal Information</h4>
            <div class="mb-3">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="fullName" placeholder="Jane Doe" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="email" placeholder="jane@example.com" />
            </div>
            <div class="mb-3">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="phone" placeholder="(555) 123-4567" />
            </div>
            <div class="mb-3">
                <label class="form-label">Address <span class="text-danger">*</span></label>
                <input class="form-control" @bind="address" placeholder="123 Main St, City, State" />
            </div>
            <div class="d-flex justify-content-end">
                <button class="btn btn-primary" @onclick="NextFromStep1" disabled="@isValidating">
                    @if (isValidating)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span> @:Validating…
                    }
                    else
                    {
                        @:Next →
                    }
                </button>
            </div>
        </section>
    }

    @* ───── Step 2: Work History ───── *@
    @if (currentStep == 2)
    {
        <section>
            <h4>Work History</h4>
            @for (int i = 0; i < workEntries.Count; i++)
            {
                var idx = i;
                var entry = workEntries[idx];
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Position @(idx + 1)</h6>
                            @if (workEntries.Count > 1)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                            }
                        </div>
                        <div class="row g-3">
                            <div class="col-md-6">
                                <label class="form-label">Company <span class="text-danger">*</span></label>
                                <input class="form-control" value="@entry.Company"
                                       @onchange="e => UpdateWork(idx, entry with { Company = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input class="form-control" value="@entry.Title"
                                       @onchange="e => UpdateWork(idx, entry with { Title = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                                       @onchange="e => UpdateWork(idx, entry with { StartDate = ParseDate((string?)e.Value) })" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                                       disabled="@entry.IsCurrent"
                                       @onchange="e => UpdateWork(idx, entry with { EndDate = ParseNullableDate((string?)e.Value) })" />
                            </div>
                            <div class="col-md-4 d-flex align-items-end">
                                <div class="form-check mb-2">
                                    <input class="form-check-input" type="checkbox" checked="@entry.IsCurrent"
                                           @onchange="e => UpdateWork(idx, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                                    <label class="form-check-label">Currently working here</label>
                                </div>
                            </div>
                            <div class="col-12">
                                <label class="form-label">Description</label>
                                <textarea class="form-control" rows="2" value="@entry.Description"
                                          @onchange="e => UpdateWork(idx, entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
                            </div>
                        </div>
                    </div>
                </div>
            }
            <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PrevStep">← Back</button>
                <button class="btn btn-primary" @onclick="NextFromStep2">Next →</button>
            </div>
        </section>
    }

    @* ───── Step 3: References ───── *@
    @if (currentStep == 3)
    {
        <section>
            <h4>References</h4>
            @for (int i = 0; i < references.Count; i++)
            {
                var idx = i;
                var refEntry = references[idx];
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Reference @(idx + 1)</h6>
                            @if (references.Count > 2)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                            }
                        </div>
                        <div class="row g-3">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" value="@refEntry.Name"
                                       @onchange="e => UpdateRef(idx, refEntry with { Name = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" value="@refEntry.Relationship"
                                       @onchange="e => UpdateRef(idx, refEntry with { Relationship = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" value="@refEntry.Email"
                                       @onchange="e => UpdateRef(idx, refEntry with { Email = (string?)e.Value ?? string.Empty })" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" value="@refEntry.Phone"
                                       @onchange="e => UpdateRef(idx, refEntry with { Phone = (string?)e.Value ?? string.Empty })" />
                            </div>
                        </div>
                    </div>
                </div>
            }
            @if (references.Count < 3)
            {
                <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
            }
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PrevStep">← Back</button>
                <button class="btn btn-primary" @onclick="NextFromStep3">Next →</button>
            </div>
        </section>
    }

    @* ───── Step 4: Cover Letter ───── *@
    @if (currentStep == 4)
    {
        <section>
            <h4>Cover Letter</h4>
            <div class="mb-2">
                <textarea class="form-control" rows="10" maxlength="2000" @bind="coverLetter"
                          placeholder="Write your cover letter here…"></textarea>
            </div>
            <div class="text-muted mb-3">@(coverLetter?.Length ?? 0) / 2000 characters</div>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PrevStep">← Back</button>
                <button class="btn btn-primary" @onclick="NextFromStep4">Next →</button>
            </div>
        </section>
    }

    @* ───── Step 5: Review & Submit ───── *@
    @if (currentStep == 5 && !submitted)
    {
        <section>
            <h4>Review Your Application</h4>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Personal Information</strong>
                    <button class="btn btn-link btn-sm p-0" @onclick='() => GoToStep(1)'>Edit</button>
                </div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@address</dd>
                    </dl>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Work History</strong>
                    <button class="btn btn-link btn-sm p-0" @onclick='() => GoToStep(2)'>Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var entry in workEntries)
                    {
                        <div class="mb-3">
                            <strong>@entry.Title</strong> at <em>@entry.Company</em><br />
                            <small class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") –
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                            </small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mt-1 mb-0">@entry.Description</p>
                            }
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>References</strong>
                    <button class="btn btn-link btn-sm p-0" @onclick='() => GoToStep(3)'>Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var r in references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> (@r.Relationship)<br />
                            <small>@r.Email · @r.Phone</small>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Cover Letter</strong>
                    <button class="btn btn-link btn-sm p-0" @onclick='() => GoToStep(4)'>Edit</button>
                </div>
                <div class="card-body">
                    <p style="white-space: pre-wrap;">@coverLetter</p>
                </div>
            </div>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PrevStep">← Back</button>
                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@isSubmitting">
                    @if (isSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span> @:Submitting…
                    }
                    else
                    {
                        @:Submit Application
                    }
                </button>
            </div>
        </section>
    }

    @* ───── Confirmation ───── *@
    @if (submitted)
    {
        <section class="text-center py-5">
            <div class="mb-3" style="font-size: 3rem; color: #198754;">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@applicationId</strong>.</p>
            <p class="text-muted">We'll be in touch soon. Thank you for applying!</p>
        </section>
    }
</div>

@code {
    private static readonly string[] StepLabels = ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];
    private const int TotalSteps = 5;

    private int currentStep = 1;
    private string? errorMessage;
    private bool isValidating;
    private bool isSubmitting;
    private bool submitted;
    private int applicationId;

    // Step 1
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2
    private List<WorkEntryForm> workEntries = [new()];

    // Step 3
    private List<ReferenceForm> references = [new(), new()];

    // Step 4
    private string coverLetter = string.Empty;

    // ── Navigation ──

    private void GoToStep(int step)
    {
        if (step >= 1 && step < currentStep && !submitted)
        {
            errorMessage = null;
            currentStep = step;
        }
    }

    private void PrevStep()
    {
        errorMessage = null;
        if (currentStep > 1) currentStep--;
    }

    // ── Step 1 validation ──

    private async Task NextFromStep1()
    {
        errorMessage = null;
        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email) ||
            string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(email);
            if (!valid)
            {
                errorMessage = "Please enter a valid email address.";
                return;
            }
            currentStep = 2;
        }
        finally
        {
            isValidating = false;
        }
    }

    // ── Step 2 ──

    private void AddWorkEntry() => workEntries.Add(new WorkEntryForm());

    private void RemoveWorkEntry(int idx)
    {
        if (workEntries.Count > 1) workEntries.RemoveAt(idx);
    }

    private void UpdateWork(int idx, WorkEntryForm entry) => workEntries[idx] = entry;

    private void NextFromStep2()
    {
        errorMessage = null;
        foreach (var e in workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate == default)
            {
                errorMessage = "Each position must have a company, job title, and start date.";
                return;
            }
        }
        currentStep = 3;
    }

    // ── Step 3 ──

    private void AddReference()
    {
        if (references.Count < 3) references.Add(new ReferenceForm());
    }

    private void RemoveReference(int idx)
    {
        if (references.Count > 2) references.RemoveAt(idx);
    }

    private void UpdateRef(int idx, ReferenceForm entry) => references[idx] = entry;

    private void NextFromStep3()
    {
        errorMessage = null;
        foreach (var r in references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        currentStep = 4;
    }

    // ── Step 4 ──

    private void NextFromStep4()
    {
        errorMessage = null;
        currentStep = 5;
    }

    // ── Submit ──

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        errorMessage = null;
        try
        {
            var personal = new PersonalInfo(fullName, email, phone, address);
            var work = new WorkHistory(workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var refs = references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, work, refs, coverLetter);
            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            submitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    // ── Helpers ──

    private static string FormatDate(DateTime date) => date == default ? string.Empty : date.ToString("yyyy-MM-dd");
    private static string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? string.Empty;
    private static DateTime ParseDate(string? value) => DateTime.TryParse(value, out var d) ? d : default;
    private static DateTime? ParseNullableDate(string? value) => DateTime.TryParse(value, out var d) ? d : null;

    // ── Form models with mutable state ──

    private record WorkEntryForm
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private record ReferenceForm
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

