.apply-container {
    max-width: 800px;
    margin: 0 auto;
}

/* ── Step Indicator ── */

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    flex-wrap: wrap;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    padding: 0.5rem 0.75rem;
    cursor: pointer;
    transition: opacity 0.2s;
    min-width: 90px;
}

.step-item:disabled {
    cursor: default;
}

.step-item.future {
    opacity: 0.4;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    margin-bottom: 0.35rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step-item.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-label {
    font-size: 0.75rem;
    color: #6c757d;
    text-align: center;
    white-space: nowrap;
}

.step-item.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-connector {
    flex: 0 0 30px;
    height: 2px;
    background: #dee2e6;
    align-self: center;
    margin-bottom: 1.2rem;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

